`allocatePayment` with a **negative/zero current balance** (already-credited unit) and `generateStatements` with **negative expense amounts** are unexercised — both are realistic (refunds, credit notes).

```typescript
test('allocatePayment on a unit already in credit sends the whole payment to credit', () => {
  const { statements, ledgerEntries } = buildLedgerFor(0); // no charges, balance 0
  const result = allocatePayment({
    payment: { id: 'p1', unitCode: 'A', amount: 30 },
    statements,
    ledgerEntries,
  });
  assert.equal(result.status, 'credit_created');
  assert.equal(result.creditAmount, 30);
});

test('allocatePayment against an unknown unitCode is unmatched', () => {
  const { statements, ledgerEntries } = buildLedgerFor(100);
  const result = allocatePayment({
    payment: { id: 'p1', unitCode: 'ZZZ', amount: 50 },
    statements,
    ledgerEntries,
  });
  assert.equal(result.status, 'unmatched');
});

test('generateStatements with zero expenses still returns one row per unit at zero due', () => {
  const statements = generateStatements({
    period: '2026-06',
    units: [mkUnit('A', 1)],
    expenses: [],
    rules: [],
  });
  assert.equal(statements.length, 1);
  assert.equal(statements[0].totalDue, 0);
});

test('calculateWeightedAllocation with a single unit gives it the full amount exactly', () => {
  const result = calculateWeightedAllocation({ amount: 33.33, units: [mkUnit('A', 5)], getWeight: (u) => u.weights.general });
  assert.equal(result.lines[0].amount, 33.33);
});
```

