  ];
  const visible = getVisibleUnits(owner(), units, properties[0]);
  assert.deepEqual(visible.map((u) => u.id), ['A1']);
});

test('getVisibleBankTransactions is hidden entirely from owners/residents', () => {
  const txs: BankTransaction[] = [{ id: 't1', tenantId: 'tenant-a', propertyId: 'P1', date: '', amount: 0, bank: '', ref: '', description: '' }];
  assert.deepEqual(getVisibleBankTransactions(owner(), txs, properties[0]), []);
  assert.deepEqual(getVisibleBankTransactions(companyAdmin(), txs, properties[0]), txs);
});

